const now = new Date();
function madridYMD(d){ return d.toLocaleDateString('en-CA', { timeZone:'Europe/Madrid' }); }
function madridDow(d){
  const wd = new Intl.DateTimeFormat('en-US', { timeZone:'Europe/Madrid', weekday:'short' }).format(d);
  return ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].indexOf(wd);
}
function ymdToDate(s){ return new Date(s + 'T00:00:00Z'); }
function ymdFromDate(d){ return d.toISOString().substring(0,10); }
function addDays(s,n){ const d = ymdToDate(s); d.setUTCDate(d.getUTCDate()+n); return ymdFromDate(d); }
const todayYMD     = madridYMD(now);
const daysSinceMon = madridDow(now);
const weekYMD      = addDays(todayYMD, -daysSinceMon);
const lastWeekYMD  = addDays(weekYMD, -7);
const yesterdayYMD = addDays(todayYMD, -1);
const sevenDaysYMD = addDays(todayYMD, -6);
const [yy, mm]     = todayYMD.split('-');
const monthYMD     = `${yy}-${mm}-01`;
const histYMD       = addDays(todayYMD, -28);
const histOlderYMD  = addDays(todayYMD, -56);
const agedYMD       = addDays(todayYMD, -5);
return [{ json: { today_ymd:todayYMD, yesterday_ymd:yesterdayYMD, week_ymd:weekYMD, last_week_ymd:lastWeekYMD, seven_days_ymd:sevenDaysYMD, month_ymd:monthYMD, hist_ymd:histYMD, hist_older_ymd:histOlderYMD, aged_ymd:agedYMD, now_iso:now.toISOString() } }];

const acc = $('Guardar Sem. Ant.').first().json;
const manuales = $input.all().map(i => i.json).filter(Boolean);
return [{ json: { ...acc, _hist_manual: manuales } }];

const acc = $('Guardar Hist Manual').first().json;
const ia = $input.all().map(i => i.json).filter(Boolean);
return [{ json: { ...acc, _hist_ia: ia } }];

const acc = $('Guardar Hist IA').first().json;
const items = $input.all().map(i => i.json).filter(Boolean);
return [{ json: { ...acc, _hist_manual_older: items } }];

const acc = $('Guardar Hist Manual Older').first().json;
const iaOlder = $input.all().map(i => i.json).filter(Boolean);
const all = [ ...(acc._hist_manual||[]), ...(acc._hist_ia||[]), ...(acc._hist_manual_older||[]), ...iaOlder ];
return [{ json: { ...acc, _hist_manual:undefined, _hist_ia:undefined, _hist_manual_older:undefined, zd_hist: { results: all, count: all.length } } }];

const d = $input.first().json;
function ymdMad(date){ return date.toLocaleDateString('en-CA', { timeZone:'Europe/Madrid' }); }
const histRes = (d.zd_hist && Array.isArray(d.zd_hist.results)) ? d.zd_hist.results : [];
const monthYMD = d.month_ymd;
const m = new Map();
for (const t of histRes) { const c = t.created_at||t.createdAt; if(!c || ymdMad(new Date(c)) < monthYMD) continue; if(!t.organization_id) continue; m.set(t.organization_id,(m.get(t.organization_id)||0)+1); }
const ids = [...m.entries()].sort((a,b)=>b[1]-a[1]).slice(0,8).map(([id])=>id);
return [{ json: { ...d, org_ids_csv: ids.join(',') || '0' } }];

// Calcula SOLO los KPIs que no cambian durante el dia (capa historica).
const d = $input.first().json;
function count(o){ if(!o) return 0; if(typeof o.count==='number') return o.count; if(Array.isArray(o.results)) return o.results.length; return 0; }
function results(o){ return (o && Array.isArray(o.results)) ? o.results : []; }
function ymdMad(date){ return date.toLocaleDateString('en-CA',{timeZone:'Europe/Madrid'}); }
function partsMad(date){ return new Intl.DateTimeFormat('en-US',{timeZone:'Europe/Madrid',weekday:'short',hour:'2-digit',hour12:false}).formatToParts(date); }
const histRes = results(d.zd_hist);
const monthYMD = d.month_ymd, weekYMD = d.week_ymd;
const nowD = new Date();
const todayLocalYMD = ymdMad(nowD);
const todayWdStr = new Intl.DateTimeFormat('en-US',{timeZone:'Europe/Madrid',weekday:'short'}).format(nowD);
// Ayer / semana anterior
const yesterday = count(d.zd_yesterday);
const yesterdayIA = count(d.zd_yesterday_ia);
const yesterdayManual = count(d.zd_yesterday_manual);
const lastWeek = count(d.zd_last_week);
// Mes
const monthRes = histRes.filter(t => { const c=t.created_at||t.createdAt; return c && ymdMad(new Date(c))>=monthYMD; });
const month = monthRes.length;
let monthIA=0, monthManual=0;
for (const t of monthRes){ const s=String(t.subject||'').trim().toLowerCase(); if(s.startsWith('conversation with')) monthIA++; else monthManual++; }
// Hourly avg (mismo dia de semana, solo manual)
const HOURS=['09','10','11','12','13','14','15','16','17','18'];
const sums=Object.fromEntries(HOURS.map(h=>[h,0]));
for (const t of histRes){ if(!t.created_at) continue; const dt=new Date(t.created_at); if(ymdMad(dt)===todayLocalYMD) continue; const p=partsMad(dt); const wd=p.find(x=>x.type==='weekday')?.value; if(wd!==todayWdStr) continue; const s=String(t.subject||'').trim().toLowerCase(); if(s.startsWith('conversation with')) continue; const hh=p.find(x=>x.type==='hour')?.value||'00'; if(sums[hh]!==undefined) sums[hh]++; }
let sampleDays=0; const histStart=new Date((d.hist_older_ymd||d.hist_ymd)+'T12:00:00Z'); const todayStart=new Date(todayLocalYMD+'T12:00:00Z');
for (let dt=new Date(histStart); dt<todayStart; dt.setUTCDate(dt.getUTCDate()+1)){ const wd=new Intl.DateTimeFormat('en-US',{timeZone:'Europe/Madrid',weekday:'short'}).format(dt); if(wd===todayWdStr) sampleDays++; }
if(sampleDays===0) sampleDays=1;
const hourly_avg = HOURS.map(h=>({ hour:h+':00', avg: Math.round((sums[h]/sampleDays)*10)/10 }));
// Weekly stacked (dias visibles; live parchea hoy)
const DAYS=['Lun','Mar','Mié','Jue','Vie'];
const wdIdx=['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].indexOf(todayWdStr);
const lastDayIdx=Math.min(wdIdx,4);
const visible=DAYS.slice(0,lastDayIdx+1);
const sIA=Object.fromEntries(visible.map(dn=>[dn,0])), sMa=Object.fromEntries(visible.map(dn=>[dn,0]));
for (const t of histRes){ const c=t.created_at||t.createdAt; if(!c) continue; const dt=new Date(c); if(ymdMad(dt)<weekYMD) continue; const p=partsMad(dt); const wd=p.find(x=>x.type==='weekday')?.value; const idx=['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].indexOf(wd); if(idx<0||idx>4||idx>lastDayIdx) continue; const dn=DAYS[idx]; const s=String(t.subject||'').trim().toLowerCase(); if(s.startsWith('conversation with')) sIA[dn]++; else sMa[dn]++; }
const weekly_stacked = visible.map(dn=>({ day:dn, ia:sIA[dn], manual:sMa[dn], total:sIA[dn]+sMa[dn], pct_ia:(sIA[dn]+sMa[dn])>0?Math.round(sIA[dn]/(sIA[dn]+sMa[dn])*100):0 }));
// ────── Tickets por tipo del mes (custom field 26672700540829): top 5 + 'Otros tipos', excluye sin tipo ──────
const TYPE_FIELD_ID = 26672700540829;
const TYPE_LABELS = { formacion:'Formación', incidencia_dev:'Incidencia Dev', incidencia_soporte:'Incidencia Soporte', 'consulta_técnica':'Consulta técnica', comercial_:'Comercial', funcionalidad:'Funcionalidad', otros:'Otros', integracion_tpv:'Integración TPV', facturacion:'Facturación' };
function typeLabel(tag){ return TYPE_LABELS[tag] || String(tag).replace(/_+$/,'').replace(/_/g,' ').replace(/^\w/,c=>c.toUpperCase()); }
function typeTag(t){ const cf=Array.isArray(t.custom_fields)?t.custom_fields.find(f=>f&&Number(f.id)===TYPE_FIELD_ID):null; return (cf&&cf.value)||null; }
const typeCount=new Map();
for (const t of monthRes){ const val=typeTag(t); if(!val) continue; typeCount.set(val,(typeCount.get(val)||0)+1); }
const _typeTotal=[...typeCount.values()].reduce((a,b)=>a+b,0);
const _typeSorted=[...typeCount.entries()].sort((a,b)=>b[1]-a[1]);
const _typeTop=_typeSorted.slice(0,5); const _typeRest=_typeSorted.slice(5).reduce((a,[,c])=>a+c,0);
const _typePct=n=>_typeTotal?Math.round(n/_typeTotal*100):0;
const _typeSlices=_typeTop.map(([tag,count])=>({ label:typeLabel(tag), count, pct:_typePct(count) }));
if(_typeRest>0) _typeSlices.push({ label:'Otros tipos', count:_typeRest, pct:_typePct(_typeRest) });
const tickets_by_type={ total_clasificados:_typeTotal, slices:_typeSlices };
// Categorías del donut (orden) + mapeo de cada tag a su segmento (top5 o 'Otros tipos')
const donutLabels = _typeSlices.map(s=>s.label);
const topLabelSet = new Set(_typeTop.map(([tag])=>typeLabel(tag)));
function categoryOf(tag){ const l=typeLabel(tag); return topLabelSet.has(l)?l:'Otros tipos'; }
// ────── Top orgs del mes (SOLO tickets con tipo) + desglose por tipo ──────
const orgTypeCount=new Map(); const orgClasTotal=new Map();
for (const t of monthRes){ if(!t.organization_id) continue; const val=typeTag(t); if(!val) continue; const cat=categoryOf(val); if(!orgTypeCount.has(t.organization_id)) orgTypeCount.set(t.organization_id,new Map()); const m=orgTypeCount.get(t.organization_id); m.set(cat,(m.get(cat)||0)+1); orgClasTotal.set(t.organization_id,(orgClasTotal.get(t.organization_id)||0)+1); }
const orgMap=new Map(); const orgsR=(d.zd_orgs&&Array.isArray(d.zd_orgs.organizations))?d.zd_orgs.organizations:[]; for(const o of orgsR){ if(o&&o.id) orgMap.set(o.id,o.name); }
const topIds=[...orgClasTotal.entries()].sort((a,b)=>b[1]-a[1]).slice(0,8);
const top_orgs=topIds.map(([id,c])=>{ const m=orgTypeCount.get(id)||new Map(); const by_type={}; for(const lbl of donutLabels){ const v=m.get(lbl)||0; if(v>0) by_type[lbl]=v; } return { name:orgMap.get(id)||`Organización ${id}`, count:c, by_type }; });
const hist_payload = { hist_generated_at:new Date().toISOString(), hist_ticket_count:histRes.length, tickets_yesterday:yesterday, tickets_yesterday_ia:yesterdayIA, tickets_yesterday_manual:yesterdayManual, tickets_last_week:lastWeek, tickets_month:month, tickets_month_ia:monthIA, tickets_month_manual:monthManual, hourly_avg, weekly_stacked, top_orgs, tickets_by_type };
return [{ json: hist_payload }];
